import{c as o,Q as t,j as a,m as d}from"./chunks/framework.D9IbVcwA.js";const u=JSON.parse('{"title":"014-driver-keyboard-3 · 键盘驱动","description":"","frontmatter":{"title":"014-driver-keyboard-3 · 键盘驱动"},"headers":[],"relativePath":"hands-on/014-driver-keyboard-3.md","filePath":"hands-on/014-driver-keyboard-3.md","lastUpdated":1779686691000}'),r={name:"hands-on/014-driver-keyboard-3.md"};function l(i,e,n,c,p,s){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="_014-3-事件驱动-irq1-处理、环形缓冲区与键盘回显" tabindex="-1">014-3 事件驱动：IRQ1 处理、环形缓冲区与键盘回显 <a class="header-anchor" href="#_014-3-事件驱动-irq1-处理、环形缓冲区与键盘回显" aria-label="Permalink to &quot;014-3 事件驱动：IRQ1 处理、环形缓冲区与键盘回显&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>前两章我们搭好了全部基础：8042 控制器初始化完成，IRQ1 绑定到位，扫描码查找表和 modifier 跟踪逻辑都已就绪。这一章要把整条数据通路彻底打通：从 IRQ1 中断触发开始，handler 读取扫描码、解码、构建 KeyEvent、入队到环形缓冲区，然后 kernel_main 的轮询循环从缓冲区取出事件，回显到屏幕上。完成这一章后，你在 QEMU 窗口里敲键盘，屏幕上就会出现对应的字符——这是内核第一次真正&quot;响应&quot;外部输入。</p><p>知识前置：前两章的所有内容。你需要理解扫描码集 1 的 make/break 规则、查找表的设计、modifier 跟踪机制，以及环形缓冲区的基本原理。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="环形缓冲区-ring-buffer" tabindex="-1">环形缓冲区（Ring Buffer） <a class="header-anchor" href="#环形缓冲区-ring-buffer" aria-label="Permalink to &quot;环形缓冲区（Ring Buffer）&quot;">​</a></h3><p>中断处理函数和主循环运行在不同的&quot;上下文&quot;中——一个在 IRQ1 的中断栈上，一个在内核主栈上。我们需要一个机制让这两边安全地传递数据，这个机制就是环形缓冲区。</p><p>环形缓冲区的原理是：一个固定大小的数组（我们用 64 个 KeyEvent 槽位），加上一个 head 指针（读位置）和一个 tail 指针（写位置）。enqueue 操作在 tail 位置写入数据，然后 tail 前进一步（对 64 取模实现回绕）。poll 操作从 head 位置读取数据，然后 head 前进一步。当 head == tail 时，缓冲区为空；当 tail 的下一个位置是 head 时，缓冲区满了——此时 enqueue 选择丢弃新事件而不是覆盖旧数据。</p><p>这意味着实际容量是 63 个事件（64 - 1，有一个槽位被&quot;浪费&quot;来区分满和空）。对于正常打字速度来说 63 个事件绑绑有余，但如果主循环被阻塞了太久（比如在做一个很长的计算），快速连续打字可能会丢事件。这是一个合理的权衡——比起阻塞中断（会导致丢失更多键），丢几个按键是可以接受的。</p><h3 id="eoi-时序的重要性" tabindex="-1">EOI 时序的重要性 <a class="header-anchor" href="#eoi-时序的重要性" aria-label="Permalink to &quot;EOI 时序的重要性&quot;">​</a></h3><p>在 IRQ1 handler 中，EOI 的发送时序至关重要。你必须先从端口 0x60 读走扫描码，然后再发 EOI。如果反过来——先发 EOI 再读端口——PIC 可能在你读完之前就允许下一个 IRQ1 中断进来，导致前一个扫描码还没处理就被新的覆盖。8042 控制器的输出缓冲区只有一个字节深度，读慢了真的会丢数据。</p><p>另外，扩展键前缀 0xE0 被跳过时也要发 EOI。如果不发，PIC 会认为 IRQ1 还在服务中，后续所有 IRQ1（包括 0xE0 后面那个真实扫描码触发的中断）都会被 PIC 阻塞，键盘就彻底不响应了。这种 bug 非常隐蔽——你不会看到任何报错，只是键盘突然死了，而且只在按扩展键的时候才触发。</p><h3 id="主循环的-poll-模式" tabindex="-1">主循环的 poll 模式 <a class="header-anchor" href="#主循环的-poll-模式" aria-label="Permalink to &quot;主循环的 poll 模式&quot;">​</a></h3><p>kernel_main 的主循环采用经典的&quot;中断驱动 + 轮询消费&quot;模式：CPU 用 <code>hlt</code> 指令休眠等待中断，被唤醒后检查环形缓冲区是否有事件。<code>while (Keyboard::poll(ev))</code> 会一直 poll 到缓冲区为空，对每个事件检查 <code>ev.pressed &amp;&amp; ev.ascii != 0</code>——只有&quot;按下&quot;且&quot;有 ASCII 映射&quot;的事件才会被 <code>console.putc()</code> 显示。</p><p>这意味着 modifier 键的按下/释放不会产生任何可见输出（因为它们的 <code>ascii</code> 为 0），功能键也不会（同样 <code>ascii</code> 为 0），按键释放也不会（<code>pressed</code> 为 false）。只有真正的可打印字符按键——字母、数字、标点、空格、回车、退格——才会回显到屏幕上。</p><p>之所以要在一个 <code>hlt</code> 唤醒后排空所有事件，是因为按键事件可能在 CPU 醒来之前就积攒了好几个——一次按键会产生 make code 和 break code 两个中断，如果主循环每次只 poll 一个事件，第二个事件就要等到下一次 <code>hlt</code> 唤醒才能处理，延迟感会很明显。</p><p>参考：</p><ul><li><a href="https://wiki.osdev.org/PS/2_Keyboard" target="_blank" rel="noreferrer">OSDev Wiki - PS/2 Keyboard</a></li><li><a href="https://wiki.osdev.org/8259_PIC" target="_blank" rel="noreferrer">OSDev Wiki - 8259 PIC</a></li></ul><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-实现-irq1-handler-——-扫描码解码与-enqueue" tabindex="-1">Step 1: 实现 IRQ1 handler —— 扫描码解码与 enqueue <a class="header-anchor" href="#step-1-实现-irq1-handler-——-扫描码解码与-enqueue" aria-label="Permalink to &quot;Step 1: 实现 IRQ1 handler —— 扫描码解码与 enqueue&quot;">​</a></h3><p><strong>目标</strong>: 编写中断处理函数，完成从原始扫描码到 KeyEvent 的完整转换链路。</p><p><strong>设计思路</strong>: 当 IRQ1 触发时，handler 需要做以下几件事：</p><p>首先，从数据端口 0x60 读取一个字节的扫描码——这个字节就是 8042 翻译后的集 1 扫描码。读操作必须在发送 EOI 之前完成，因为如果先发 EOI，新的 IRQ1 可能在你读完 0x60 之前就到达了，导致当前扫描码被覆盖。</p><p>然后，检查是否是扩展前缀 0xE0。如果是，直接发送 EOI 然后返回——我们选择忽略所有扩展键。注意 0xE0 会触发一次 IRQ1，后面的实际扫描码会触发第二次 IRQ1，所以一个扩展按键会调用两次 handler，第一次被忽略，第二次的扫描码不是 0xE0 所以会被正常处理——但此时 make code 的含义已经不对了（因为它本来是 0xE0 后面跟着的键码，不是独立的键码）。为了彻底避免这个问题，我们的做法是：遇到 0xE0 就跳过整个事件，不做任何 enqueue。这样扩展键的第二次中断处理的是一个孤立的扫描码，它会被当作一个普通键来解码——但由于大多数扩展键的扫描码在查找表中映射为 0（比如方向键），所以实际上不会产生错误的 ASCII 输出。</p><p>接下来，判断按下还是松开：bit 7 为 0 是按下，为 1 是松开。提取 make code：和 0x7F 做 AND。</p><p>然后是 modifier 跟踪：如果 make code 是左 Shift（0x2A）或右 Shift（0x36），更新 <code>shift_held_</code> 为 pressed 的值。如果是左 Ctrl（0x1D），更新 <code>ctrl_held_</code>。如果是左 Alt（0x38），更新 <code>alt_held_</code>。注意这一步必须在构建 KeyEvent 之前完成，因为我们需要&quot;当前的&quot;modifier 状态。</p><p>构建 KeyEvent：填入 scancode、pressed、三个 modifier 的当前值。ASCII 翻译只在按键按下且 make code &lt; 128 时执行：如果 <code>shift_held_</code> 为真，查 <code>kScToUpper</code>，否则查 <code>kScToLower</code>。松开事件的 ascii 固定为 0。</p><p>最后，调用 <code>enqueue()</code> 把事件放进环形缓冲区，然后调用 <code>PIC::send_eoi(1)</code> 通知 PIC 中断处理完毕。</p><p><strong>实现约束</strong>: handler 的签名是 <code>static void irq1_handler(cinux::arch::InterruptFrame* frame)</code>。参数 <code>frame</code> 我们不用（键盘中断不需要中断帧中的信息），但签名必须和汇编 stub 调用的约定一致。所有操作都是确定性的，不涉及动态内存分配或者阻塞等待。</p><p><strong>踩坑预警</strong>: EOI 必须在读扫描码之后发送。如果你先发 EOI 再读端口 0x60，有可能在两者之间又来了一个 IRQ1，此时你再读 0x60 拿到的就是新扫描码，旧的就丢了。另外一个容易忽略的点：modifier 跟踪对松开事件也要处理。如果 Shift 按下时设置了 <code>shift_held_ = true</code>，但松开时忘了设置 <code>shift_held_ = false</code>，那之后所有按键都会被当作 Shift 被按下的状态来翻译——你会发现打出来的全是大写字母和符号，而且永远不会恢复。</p><p><strong>验证</strong>: 运行 QEMU in-kernel 测试（<code>ctest</code> 的 kernel 测试部分），test_keyboard.cpp 中的解码测试应该通过。关键测试用例包括：扫描码 0x1E 产生 ascii=&#39;a&#39;、pressed=true；扫描码 0x9E 产生 pressed=false、ascii=0；先发 0x2A（Shift 按下）再发 0x1E（A 按下）产生 ascii=&#39;A&#39;、shift=true。</p><h3 id="step-2-实现环形缓冲区的-enqueue-和-poll" tabindex="-1">Step 2: 实现环形缓冲区的 enqueue 和 poll <a class="header-anchor" href="#step-2-实现环形缓冲区的-enqueue-和-poll" aria-label="Permalink to &quot;Step 2: 实现环形缓冲区的 enqueue 和 poll&quot;">​</a></h3><p><strong>目标</strong>: 编写环形缓冲区的写入和读取操作。</p><p><strong>设计思路</strong>: <code>enqueue()</code> 的工作是：计算 tail 的下一个位置 <code>next = (tail + 1) % SIZE</code>。如果 <code>next == head</code>，说明缓冲区满了，直接返回（丢弃事件）。否则在 <code>queue_[tail]</code> 写入事件，然后 <code>tail = next</code>。<code>poll()</code> 的工作是：如果 <code>head == tail</code>，返回 false（缓冲区空）。否则从 <code>queue_[head]</code> 读出事件到输出参数，然后 <code>head = (head + 1) % SIZE</code>，返回 true。</p><p>这两个函数不需要锁或者原子操作，因为我们的执行环境保证了安全：enqueue 只在 IRQ1 handler 中被调用（中断上下文），poll 只在 kernel_main 的主循环中被调用（正常上下文）。x86 的单字节写入是原子的，而且 <code>cli</code>/<code>sti</code> 和中断门本身就保证了 enqueue 不会被 poll 的执行打断（反过来可以：poll 被 enqueue 打断是安全的，因为 enqueue 只修改 tail 而 poll 只修改 head）。</p><p><strong>实现约束</strong>: 两个方法都是 Keyboard 类的 static 方法。缓冲区大小用 <code>static constexpr uint32_t KEY_QUEUE_SIZE = 64</code> 定义。取模运算可以用 <code>%</code> 操作符（编译器会优化为位运算，因为 64 是 2 的幂）。<code>enqueue</code> 是 private 方法，只有 irq1_handler 可以调用。<code>poll</code> 是 public 方法，供外部调用。</p><p><strong>踩坑预警</strong>: 环形缓冲区最经典的 bug 是&quot;满/空判断混淆&quot;。head == tail 既可能是空也可能是满——这取决于你是先写再推进 tail，还是先推进 tail 再写。我们采用的是&quot;先写再推进&quot;的方式，判断满的条件是 <code>tail+1 == head</code>。如果你把判断条件写反了，要么永远不认为满了（导致覆盖未读数据），要么永远认为满了（导致所有事件被丢弃）。另外，取模千万别忘了——如果 tail 一直加到超过 63 然后变成 64、65、66...，数组就越界了。</p><p><strong>验证</strong>: host 端测试中的 ring buffer 测试用例应该覆盖这些场景：空缓冲区 poll 返回 false、单个事件 enqueue+poll 正确、多个事件 FIFO 顺序正确、缓冲区满时丢弃事件、缓冲区回绕后仍然正确。如果你自己写测试，可以构造一个&quot;填满 63 个事件 -&gt; 尝试填第 64 个 -&gt; 验证被丢弃 -&gt; 逐个 poll 验证前 63 个&quot;的场景。</p><h3 id="step-3-实现-kernel-main-的键盘轮询循环" tabindex="-1">Step 3: 实现 kernel_main 的键盘轮询循环 <a class="header-anchor" href="#step-3-实现-kernel-main-的键盘轮询循环" aria-label="Permalink to &quot;Step 3: 实现 kernel_main 的键盘轮询循环&quot;">​</a></h3><p><strong>目标</strong>: 在内核主循环中轮询键盘事件并回显到屏幕。</p><p><strong>设计思路</strong>: 前一章我们把 kernel_main 的 idle loop 改成了 <code>while(1) { hlt; }</code>，这是一个 WFI（Wait For Interrupt）模式——CPU 执行 <code>hlt</code> 指令进入低功耗状态，直到下一个中断到来时被唤醒。现在我们要在每次被唤醒之后，把环形缓冲区里所有待处理的事件全部排空。具体做法是：<code>hlt</code> 之后接一个 while 循环，反复调用 <code>Keyboard::poll(ev)</code>，直到返回 false（缓冲区空了）。对于每个取出的事件，只处理&quot;按下且 ascii 非零&quot;的情况——调用 <code>console.putc(ev.ascii)</code> 把字符输出到屏幕。松开事件和非打印键事件被忽略。</p><p>这样整个数据通路就打通了：按键 -&gt; 8042 翻译扫描码 -&gt; IRQ1 中断 -&gt; handler 解码并 enqueue -&gt; 主循环 poll 取出 -&gt; console.putc 输出到屏幕。由于 kprintf 已经注册了 Console 作为输出后端，所以屏幕和串口会同步显示你输入的字符。</p><p><strong>实现约束</strong>: 在 <code>kernel/main.cpp</code> 的 while 循环中，<code>hlt</code> 之后添加 poll 循环。需要声明一个 <code>KeyEvent ev</code> 变量（循环外部，避免每次重新分配）。<code>console.putc()</code> 调用需要确保 <code>console</code> 变量在这个位置是可访问的——它是在前面 Console 初始化时声明的局部变量。</p><p><strong>踩坑预警</strong>: <code>console.putc()</code> 不能在中断上下文中被调用——它操作帧缓冲区，而帧缓冲区的滚动操作涉及大量内存拷贝，如果在 IRQ handler 中做这些事，中断延迟会变得非常大。所以我们严格遵循&quot;中断只 enqueue、主循环做渲染&quot;的原则。另外，poll 循环必须是一个 while 而不是 if——因为一次中断唤醒之后可能积攒了多个事件（比如你快速按了好几个键，或者扩展键触发了两次 IRQ1 但第一次被跳过了），必须全部排空。</p><p><strong>验证</strong>: 构建并启动 QEMU。在 QEMU 窗口中点击一下让它获得键盘焦点，然后按下任意字母键——屏幕上应该出现对应的字符。按下 Shift+A，应该出现大写 &#39;A&#39;。按下回车键，屏幕应该换行。按下退格键，光标应该回退。串口输出应该同步显示相同的内容。</p><p>完整验证步骤：启动 QEMU -&gt; 点击窗口获取焦点 -&gt; 依次输入 <code>hello</code> -&gt; 屏幕显示 <code>hello</code> -&gt; 按回车 -&gt; 换行 -&gt; 按 Shift+1 -&gt; 屏幕显示 <code>!</code>。如果一切正常，恭喜，你的内核第一次&quot;听&quot;到了你的声音。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>构建后启动 QEMU，观察初始化日志中键盘相关的部分。然后点击 QEMU 窗口获取键盘焦点（这个很重要——如果焦点不在 QEMU 窗口上，按键事件会被宿主系统截获），开始打字。你应该能看到每一个可打印字符都出现在屏幕上。</p><p>如果你同时想看 host 端测试，运行：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmake --build build &amp;&amp; cd build &amp;&amp; ctest -L keyboard --output-on-failure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会运行 host 端测试，覆盖扫描码翻译、modifier 跟踪、环形缓冲区操作等所有逻辑。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>按键没反应（屏幕无输出）</strong>: 首先检查串口日志——如果 <code>[KBD]</code> 初始化日志正常出现了，说明控制器初始化没问题。然后在 kernel_main 的 poll 循环中加一条调试日志（比如在 <code>Keyboard::poll(ev)</code> 返回 true 时打印 <code>ev.scancode</code> 和 <code>ev.ascii</code>），看看是不是 handler 根本没被调用（说明 IRQ1 没有到达）还是 handler 调用了但 poll 取不到事件（说明 enqueue 有问题）。如果 handler 没被调用，检查 <code>PIC::unmask(1)</code> 是否被调用了、<code>sti</code> 是否执行了。</p><p><strong>按键输出乱码</strong>: 大概率是查找表填错了。用 host 端测试验证 <code>kScToLower[0x1E] == &#39;a&#39;</code> 和 <code>kScToUpper[0x1E] == &#39;A&#39;</code>。如果这些基本映射都错了，检查表的索引排列——确保你把值填在了正确的偏移位置上。</p><p><strong>Shift 键&quot;粘住&quot;（一直是大写）</strong>: 说明 Shift 的 break code 没有被正确处理。检查 modifier 跟踪逻辑：在收到 0xAA（左 Shift 松开）时，<code>shift_held_</code> 应该被设为 false。如果条件判断里只检查了 make code 而没有检查 pressed 状态，Shift 的按下和松开都会设为 true。</p><p><strong>第一个按键丢失</strong>: 这可能是因为初始化时输出缓冲区里有一个残留字节没有被 flush 掉。检查 <code>Keyboard::init()</code> 的第二步（刷新输出缓冲区）是否正确实现——应该循环读取直到状态寄存器 bit 0 变为 0。</p><p><strong>ring buffer 测试失败</strong>: 如果 host 端测试中 wrap-around 测试失败了，检查取模运算是否正确——<code>% KEY_QUEUE_SIZE</code> 中的 KEY_QUEUE_SIZE 必须是 64。如果你不小心写成了 63 或者 65，回绕点就错了。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>关键点</th></tr></thead><tbody><tr><td>IRQ1 handler</td><td>读 0x60 -&gt; 检查 0xE0 -&gt; make/break 判定 -&gt; modifier 更新 -&gt; ASCII 翻译 -&gt; enqueue -&gt; EOI</td></tr><tr><td>环形缓冲区</td><td>64 槽位，容量 63，head/tail 指针，满时丢弃</td></tr><tr><td>EOI 时序</td><td>先读 0x60 再发 PIC::send_eoi(1)，防止扫描码被覆盖</td></tr><tr><td>Poll 循环</td><td>hlt 唤醒后 while(poll(ev)) 排空缓冲区，只回显 pressed &amp;&amp; ascii!=0</td></tr><tr><td>扩展键 0xE0</td><td>检测到直接跳过，发 EOI 返回，不 enqueue</td></tr><tr><td>中断 vs 主循环</td><td>handler 只做 enqueue，渲染留给主循环，避免中断延迟</td></tr></tbody></table>',59)])])}const q=o(r,[["render",l]]);export{u as __pageData,q as default};
